




































import { Vue, Component, Provide, Watch } from 'vue-property-decorator';
import Intro from '@/components/intro/Intro.vue';
import Banner from '@/components/banner/Banner.vue';
import Navbar from '@/components/nav/Navbar.vue';
import Skill from '@/components/exp/Skill.vue';
import { State, Mutation } from 'vuex-class';
import Gallery from '@/components/gallery/Gallery.vue';
import Experience from '@/components/exp/Experience.vue';
import Contact from './components/contact/Contact.vue';
import VueFooter from './components/footer/VueFooter.vue';

@Component({
  name:'App',
  components:{
    Navbar,
    Banner,
    Intro,
    Skill,
    Gallery,
    Experience,
    Contact,
    VueFooter
  }
})
export default class App extends Vue {
  @Provide("scroll") scrollOffset: any={ offsetY: 0, size:0};
  @State("menu") menu: any;
  @Mutation("menu") setMenu:any;
  @Mutation("disableMenu") setMenuDisabled: any;
  private _timer: any=null;
  introOffset: number=1000;
  navigatable: boolean=false;
  fab: boolean=false;
  mounted(){
    window.addEventListener("scroll", this.onscroll,false);
    window.addEventListener("resize", this.onresize,false);
    var intro=this.$refs.intro as Intro;
    this.introOffset= intro.$el.offsetTop;
  }

  onViewMore (){
    let el=this.$refs.intro as Intro;
    setTimeout(()=>{
      el.scrollTo();
    },400);
  }

  @Watch("menu")
  onMenuChanged(){
    if (this.menu && this.navigatable){
      let el=this.$refs[this.menu] as any;
      if (el){
        setTimeout(()=>{
          el.scrollTo();
          this.setMenuDisabled(true);
        },50);
        setTimeout(()=>{
          this.setMenuDisabled(false);
        },1400);
      }
    }
  }

  onscroll(){
    if (this._timer)
      clearTimeout(this._timer);
    this._timer=setTimeout(()=>{
      let offsetY=window.scrollY;
      this.scrollOffset.offsetY=offsetY;
      if (offsetY>=this.introOffset-50){
        this.fab=true;
      }
      else this.fab=false;
    },75);
  }
  onresize(){
    this.onscroll();
    let intro=this.$refs.intro as Intro;
    if (intro.$el)
      this.introOffset= intro.$el.offsetTop;
    this.scrollOffset.size=window.innerHeight+window.innerWidth;
    this.onMenuChanged();
  }

  onAnimated(){
    this.navigatable=true;
  }

  gotoTop(){
    this.setMenu("intro");
    setTimeout(function(){
      window.scrollTo({
        top:0,
        behavior:"smooth"
      });
    },100);
  }
}
