
















import { Vue, Component, Prop, Watch, Inject } from 'vue-property-decorator';
import { NavigationList } from '@/models/navigationList';
import { State, Mutation } from 'vuex-class';

@Component
export default class Navbar extends Vue {
    @Prop({default: 1000}) visibleOffset: number;
    @Inject("scroll") scrollOffset: any;
    @State("menu") menu: any;
    @State("disableMenu") disableMenu: boolean;
    @Mutation("menu") setMenu: any;
    el: any=null;
    mini: boolean=true;
    drawer: any=null;
    owner: string="Darick Nguyen";
    menuList = NavigationList;
    mounted(){
        this.el= this.$refs.el;
    }

    scrollTo(){
        window.scrollTo({
            top: this.el.offsetTop,
            behavior:  'smooth'
        });
    }

    // @Watch("menu")
    // onStateMenuChanged(){
    //     this.currentActive=this.menu;
    // }
    
    get currentActive(){
        return this.menu;
    }
    set currentActive(val: string){
        this.setMenu(val);
    }

    @Watch("offsetY")
    onScroll(){
        if (this.offsetY>=this.visibleOffset-50)
            this.drawer=true;
        else this.drawer=false;
    }

    get offsetY(){
        return this.scrollOffset["offsetY"];
    }
}
