













































































import { Vue, Component, Inject } from "vue-property-decorator";
import { Mutation, State } from 'vuex-class';
import { ExperienceList, LifeEvent, ExperienceItem } from '@/models/experienceList';

@Component
export default class Experience extends Vue {
    @Inject("scroll") scrollOffset: any;
    @Mutation("menu") setMenu: any;
    el: any = null;
    list: ExperienceItem[]= ExperienceList;
    lifeEvent= LifeEvent;
    stars: any=[];
    private downCap: number=270;
    private leftCap: number=240;
    private holdDurationFactor: number=12;
    private loopTime=300;
  mounted() {
    this.el = this.$refs.el;
    this.createEffect();
  }

  createEffect(){
    let eff=this.$refs.effect as any;
    let number=this.rand(32,38);
    for (let i=0; i< number; i++){
      this.stars.push({
        left: this.rand(6,45)*5,
        top: this.rand(-25,-10),
        duration: this.rand(1,10)*1000+9000,
        delay: this.rand(0,10)*1000,
        width: this.rand(1,4),
        currentRight: 0,
        currentDown:0,
        currentDelay:0,
      });
    }
    var refEle=eff;
      eff.addEventListener("mouseenter",function(){
        refEle.className="effect-behind hover";
      },false);
      eff.addEventListener("mouseleave",function(){
        refEle.className="effect-behind";
      },false);
      
    let el=this.$refs.effect as Element;
    setInterval(()=>{
      if (el && (el as any).style.display!="none"){
        let elems=el.querySelectorAll(".falling-star");
        if (elems && elems.length>0){
          for (let i=0; i<elems.length; i++)
          {
            let target=elems[i] as any;
            target.style.transitionDuration=(this.loopTime)+"ms";
            let star=this.stars[i];
            let dur=star.duration;
            if (el.className.indexOf("hover")>=0)
              dur=dur*this.holdDurationFactor;
            let downSpeed=this.downCap/(dur/this.loopTime);
            let leftSpeed=this.leftCap/(dur/this.loopTime);
            if (star.currentDown>this.downCap){
              star.currentRight=0;
              star.currentDown=0;
              star.currentDelay=0;
            }
            else if (star.currentDelay>=star.delay) {
              star.currentRight+=leftSpeed;
              star.currentDown+=downSpeed;
              if (star.currentDown>=this.downCap)
              {
                target.style.opacity='0';
              }
              else 
                target.style.opacity='1';
            }
            star.currentDelay+=this.loopTime;
            target.style.transform='translateY('+star.currentDown+"vw) translateX(-"+star.currentRight+"vw) rotate(39deg)";
          }
        }
      }
    },this.loopTime);
  }

  scrollTo() {
    window.scrollTo({
      top: this.el.offsetTop-60,
      behavior: "smooth"
    });
  }

    rand(min: number=0, max: number=100): number{
        return Math.round(Math.random()*(max-min)+min);
    }
  
    get isInViewPort(){
        let offsetTop=0;
        let clientHeight=600;
        if (this.el) offsetTop=this.el.offsetTop;
        if (this.$el) clientHeight=this.$el.clientHeight;
        let result= this.offsetY>=offsetTop-clientHeight*0.3 && this.offsetY<=offsetTop+clientHeight-clientHeight*0.35;
        if (result && this.el){
            this.setMenu("exp");
            this.el.style.minHeight=this.el.clientHeight+"px";
        }
        return result;
    }

    get offsetY(){
        return this.scrollOffset.offsetY;
    }
    
    get size(){
        return this.scrollOffset.size;
    }
}
