import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    menu:'',
    disableMenu: false
  },
  mutations: {
    menu:function(state,value){
      if (!state.disableMenu)
        state.menu=value;
    },
    disableMenu: function(state, value){
      state.disableMenu=value;
    }
  },
  actions: {

  }
})
