































import Vue from "vue";
import Component from "vue-class-component";
import { Inject, Watch } from 'vue-property-decorator';
import { Mutation, State } from 'vuex-class';

@Component
export default class Intro extends Vue {
    @Inject("scroll") scrollOffset: any;
    @State("menu") menu: any;
    @Mutation("menu") setMenu: any;
    animated: boolean=false;
    el: any=null;
    mounted(){
        this.el= this.$refs.el;
    }

    scrollTo(){
        window.scrollTo({
            top: this.el.offsetTop,
            behavior:  'smooth'
        });
    }

    get isInViewPort(){
        let offsetTop=0;
        let clientHeight=600;
        if (this.el) offsetTop=this.el.offsetTop;
        if (this.$el) clientHeight=this.$el.clientHeight;
        let result= this.offsetY>=offsetTop-clientHeight*0.4 && this.offsetY<=offsetTop+clientHeight-clientHeight*0.4;
        if (result && this.el){
            this.setMenu("intro");
            this.el.style.minHeight=this.el.clientHeight+"px";
        }
        return result;
    }
    
    get offsetY(){
        return this.scrollOffset.offsetY;
    }
    get size(){
        return this.scrollOffset.size;
    }
}
