























































































































import {Vue, Component, Inject} from 'vue-property-decorator'
import { Mutation } from 'vuex-class';

@Component
export default class Contact extends Vue{
    @Inject("scroll") scrollOffset: any;
    @Mutation("menu") setMenu: any;
    el: any = null;
  mounted() {
    this.el = this.$refs.el;
  }

  scrollTo() {
    window.scrollTo({
      top: this.el.offsetTop+5,
      behavior: "smooth"
    });
  }
  
    get isInViewPort(){
        let offsetTop=0;
        let clientHeight=600;
        if (this.el) offsetTop=this.el.offsetTop;
        if (this.$el) clientHeight=this.$el.clientHeight;
        let result= this.offsetY>=offsetTop-clientHeight*0.8 && this.offsetY<=offsetTop+clientHeight-clientHeight*0.5;
        if (result && this.el){
            this.setMenu("contact");
        }
        return result;
    }

    get offsetY(){
        return this.scrollOffset.offsetY;
    }
    goto(url: string){
        window.open(url, "_");
    }
}
